CustomField.formula:
/* * Total Basic Benefit * = BIA + (BIA x age factor) * = BIA x (1 + factor) * where BIA = formula_basePay__c + 2000 * * Age source: * - Age_Option_Basic_Manual__c when no FEGLI code AND the picklist is set * - Contact_Age__c in every other case (FEGLI code set, OR manual age blank) * * Age 45+ or unset -> factor 0 -> result is just BIA (no extra benefit). */ IF( AND( OR( ISBLANK(TEXT(FEGLI_Code_Picklist__c)), TEXT(FEGLI_Code_Picklist__c) = "--" ), NOT(ISBLANK(TEXT(Age_Option_Basic_Manual__c))) ),
/* ---- Path A: manual age picklist ---- */ CASE(TEXT(Age_Option_Basic_Manual__c), "Under 35", (formula_basePay__c + 2000) * 2.0, /* factor 1.0 */ "36", (formula_basePay__c + 2000) * 1.9, /* factor 0.9 */ "37", (formula_basePay__c + 2000) * 1.8, /* factor 0.8 */ "38", (formula_basePay__c + 2000) * 1.7, /* factor 0.7 */ "39", (formula_basePay__c + 2000) * 1.6, /* factor 0.6 */ "40", (formula_basePay__c + 2000) * 1.5, /* factor 0.5 */ "41", (formula_basePay__c + 2000) * 1.4, /* factor 0.4 */ "42", (formula_basePay__c + 2000) * 1.3, /* factor 0.3 */ "43", (formula_basePay__c + 2000) * 1.2, /* factor 0.2 */ "44", (formula_basePay__c + 2000) * 1.1, /* factor 0.1 */ formula_basePay__c + 2000 /* default (45+ / unmatched) */ ),
/* ---- Path B: Contact_Age__c (computed from DOB) ---- */ IF(AND(Contact_Age__c > 0, Contact_Age__c <= 35), (formula_basePay__c + 2000) * 2.0, IF(Contact_Age__c = 36, (formula_basePay__c + 2000) * 1.9, IF(Contact_Age__c = 37, (formula_basePay__c + 2000) * 1.8, IF(Contact_Age__c = 38, (formula_basePay__c + 2000) * 1.7, IF(Contact_Age__c = 39, (formula_basePay__c + 2000) * 1.6, IF(Contact_Age__c = 40, (formula_basePay__c + 2000) * 1.5, IF(Contact_Age__c = 41, (formula_basePay__c + 2000) * 1.4, IF(Contact_Age__c = 42, (formula_basePay__c + 2000) * 1.3, IF(Contact_Age__c = 43, (formula_basePay__c + 2000) * 1.2, IF(Contact_Age__c = 44, (formula_basePay__c + 2000) * 1.1, formula_basePay__c + 2000 /* default (45+ or unset) */ )))))))))) )
